import { NgModule } from '@angular/core';
import { RouterModule } from '@angular/router';
import { ReactiveFormsModule } from '@angular/forms';
import { SharedModule } from 'app/shared/shared.module';
import { UserComponent } from 'app/users/user/user.component';
import { ChangeUserPasswordModalComponent } from './change-user-password-modal/change-user-password-modal.component';

@NgModule({
  imports: [
    SharedModule,
    ReactiveFormsModule,
    RouterModule.forChild([{ path: '', component: UserComponent }])
  ],
  declarations: [UserComponent, ChangeUserPasswordModalComponent],
  entryComponents: [ChangeUserPasswordModalComponent],
})
export class UserModule { }



