import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators as val } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { Observable } from 'rxjs/Observable';
import { User } from 'models/user';
import { UserService } from 'app/core/user.service';
import { CycleService } from 'app/core/cycle.service';
import { SnackbarService } from 'app/core/snackbar.service';
import { ChangeUserPasswordModalComponent } from './change-user-password-modal/change-user-password-modal.component';
import { MatDialog } from '@angular/material';

@Component({
  selector: 'ctb-user',
  templateUrl: './user.component.html',
  styleUrls: ['./user.component.scss']
})
export class UserComponent implements OnInit {

  userId: string;
  user$: Observable<User>;
  user: User;

  editingAccount: boolean;
  accountForm: FormGroup;
  accountFormLoading: boolean;

  constructor(
    private userService: UserService,
    private route: ActivatedRoute,
    private router: Router,
    private cycleService: CycleService,
    private snackbar: SnackbarService,
    private fb: FormBuilder,
    private dialog: MatDialog,
  ) {
    this.router.onSameUrlNavigation = 'reload';
    this.router.routeReuseStrategy.shouldReuseRoute = () => false;

    this.accountForm = this.fb.group({
      name: ['', [val.required]],
      email: ['', [val.required, val.email]],
      company: [''],
      phoneNumber: [''],
      role: [''],
      notes: [''],
    });
  }

  ngOnInit() {
    this.route.params.subscribe(params => {
      this.userId = params.id;

      this.user$ = this.userService.getById(params.id)
        .do(u => {
          this.user = u;

          // patch edit forms
          this.accountForm.patchValue({
            name: u.name,
            email: u.email,
            company: u.company,
            phoneNumber: u.phone_number,
            role: u.role,
            notes: u.notes,
          });

        })
        .share();

    });
  }

  onAccountFormSubmit(form) {
    if (form.invalid) return;
    this.accountFormLoading = false;

    const edits: any = Object.keys(form.value)
      .filter(k => form.value[k] !== this.user[k])
      .reduce((e, k) => {
        e[k] = form.value[k];
        return e;
      }, {});

    if (edits.name) {
      const name = edits.name.trim().split(' ');
      edits.first_name = name.splice(0, 1)[0];
      edits.last_name = name.join(' ');
      delete edits.name;
    }

    console.log(edits);


    this.userService.update(this.userId, edits)
      .subscribe(
        user => {
          this.accountFormLoading = false;
          this.editingAccount = false;
          this.snackbar.snack('Subscriber updated successfully.');
        },
        res => {
          const errors = Object.keys(res.error.errors)
            .reduce((e, k) => e.concat(res.error.errors[k]), []);

          this.snackbar.error(errors.join('\n'));
        }
      );
  }

  changePassword() {
    const dialogRef = this.dialog.open(ChangeUserPasswordModalComponent, {
      height: '370px',
      width: '400px',
      data: { user: this.user },
    });

  }

}



